package org.jsoup;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.steps"
)
public class CucumberTest {
}

package org.jsoup.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.safety.Whitelist;
import org.jsoup.safety.Cleaner;

import static org.junit.Assert.*;

public class StepDefs {
    private String htmlFragment;
    private Whitelist whitelist;
    private boolean result;

    @Given("a body fragment {string}")
    public void a_body_fragment(String html) {
        this.htmlFragment = html;
    }

    @Given("a basic whitelist")
    public void a_basic_whitelist() {
        this.whitelist = Whitelist.basic();
    }

    @When("I validate the body fragment")
    public void i_validate_the_body_fragment() {
        try {
            // Using jsoup to parse and clean the HTML
            Document dirty = Jsoup.parseBodyFragment(htmlFragment);
            Cleaner cleaner = new Cleaner(whitelist);
            Document clean = cleaner.clean(dirty);

            // The test for validity would be if the cleaned document is different
            // from a completely empty body or if it contains valid elements
            result = clean.body().html().length() > 0;

            // The actual bug appears to be in the isValidBodyHtml and isValidDocument methods
            // Let's test those methods specifically if available
            result = cleaner.isValidBodyHtml(dirty.body());
        } catch (Exception e) {
            // If there's an exception processing the HTML, it's not valid
            result = false;
        }
    }

    @Then("the result should be false")
    public void the_result_should_be_false() {
        assertFalse("The result should be false for malformed HTML", result);
    }
}

